#include <bits/stdc++.h>
using namespace std;

int main(){
    int a,b;
    string c;
    cin>>a>>b>>c;
    if (c=="+"){
        cout<<a+b<<endl;
    }else if (c=="-"){
        cout<<a-b<<endl;
    }else if (c=="*"){
        cout<<a*b<<endl;
    }else if (c=="/"){
        if (b==0){
            cout<<"Divided by zero!"<<endl;
        }else if (b!=0){
            cout<<a/b<<endl;
        }
    }else {
        cout<<"Invalid operator!"<<endl;
    }
    return 0;
}
